/**
 * TTN V3 → ThingsBoard Uplink Converter
 * 全自动兼容版 (支持二进制 9 字节 & 20 字节 Payload 与文本 Payload)
 */
var data;
var jsonString = "";
// =========================
// 1. 安全解析 Payload
// =========================
try {
    if (Array.isArray(payload) || (payload && typeof payload.length === 'number' && typeof payload !== 'string')) {
        for (var i = 0; i < payload.length; i++) {
            jsonString += String.fromCharCode(payload[i]);
        }
    } else if (typeof payload === 'string') {
        jsonString = payload;
    } else {
        jsonString = JSON.stringify(payload);
    }
    var cleanStr = jsonString.replace(/[\u00A0\u1680\u180e\u2000-\u200a\u2028\u2029\u202f\u205f\u3000]/g, ' ');
    data = JSON.parse(cleanStr);
} catch (e) {
    return { error: "Payload 解析失败", message: e.message, inputString: jsonString };
}

// 自动解包一层 data 壳（如果有）
if (data && data.data) {
    data = data.data;
}

// =========================
// 2. 智能提取 Device Name 与映射
// =========================
var deviceName = "lilygo"; // 兜底默认名
var devEui = "";
if (data && data.end_device_ids && data.end_device_ids.dev_eui) {
    devEui = data.end_device_ids.dev_eui;
} else if (metadata && metadata.devEui) {
    devEui = metadata.devEui;
}
if (data && data.end_device_ids && data.end_device_ids.device_id) {
    deviceName = data.end_device_ids.device_id;
} else if (metadata && metadata.deviceName) {
    deviceName = metadata.deviceName; // 从 TB integration 的 metadata 获取
} else if (metadata && metadata.device_id) {
    deviceName = metadata.device_id;
}
// --- 指定设备 ID / DevEUI 映射逻辑 ---
var checkId = (devEui || deviceName).toUpperCase();
if (checkId === "70B3D57ED00771F0") {
    deviceName = "A-001";
} else if (checkId === "70B3D57ED00771F1") {
    deviceName = "A-002";
}

var telemetry = {};
var attributes = {};

// =========================
// 3. 核心解码逻辑 (支持二进制与文本)
// =========================
var decoded = null;

// A. 尝试从 frm_payload 二进制解码
var base64Payload = null;
if (data && data.uplink_message && data.uplink_message.frm_payload) {
    base64Payload = data.uplink_message.frm_payload;
} else if (data && data.frm_payload) {
    base64Payload = data.frm_payload;
}

if (base64Payload) {
    try {
        var raw = atob(base64Payload);
        var bytes = [];
        for (var j = 0; j < raw.length; j++) {
            bytes.push(raw.charCodeAt(j));
        }
        if (bytes.length >= 9) {
            var tempRaw = (bytes[0] << 8) | bytes[1];
            if (tempRaw & 0x8000) tempRaw -= 0x10000;
            var temp = tempRaw / 10.0;

            var hum = bytes[2] / 2.0;

            var wbgtRaw = (bytes[3] << 8) | bytes[4];
            if (wbgtRaw & 0x8000) wbgtRaw -= 0x10000;
            var wetBulb = wbgtRaw / 10.0;

            var risk = bytes[5];
            var battery = bytes[6];

            var flags = bytes[7];
            var fall = (flags & 0x01) ? 1 : 0;
            var usb = (flags & 0x02) ? 1 : 0;

            var heartRateAvg = bytes[8];

            decoded = {
                temp: temp,
                hum: hum,
                wetBulb: wetBulb,
                risk: risk,
                battery: battery,
                fall: fall,
                usb: usb,
                heartRateAvg: heartRateAvg
            };

            // 扩展解析：如果包含了 20 字节，读取更多的串口同步指标
            if (bytes.length >= 20) {
                var locRaw = (bytes[9] << 8) | bytes[10];
                if (locRaw & 0x8000) locRaw -= 0x10000;
                decoded.localWBGT = locRaw / 10.0;

                var extRaw = (bytes[11] << 8) | bytes[12];
                if (extRaw & 0x8000) extRaw -= 0x10000;
                decoded.externalWBGT = extRaw / 10.0;

                var skRaw = (bytes[13] << 8) | bytes[14];
                if (skRaw & 0x8000) skRaw -= 0x10000;
                decoded.skinTemp = skRaw / 10.0;

                var tcRaw = (bytes[15] << 8) | bytes[16];
                if (tcRaw & 0x8000) tcRaw -= 0x10000;
                decoded.estimatedTc = tcRaw / 10.0;

                decoded.currentPSI = bytes[17] / 10.0;

                var chsRaw = (bytes[18] << 8) | bytes[19];
                decoded.cumulativeHeatStrain = chsRaw / 10.0;
            }
        }
    } catch (err) {
        // 忽略二进制解码错误，尝试下面文本解析
    }
}

// B. 尝试文本解析 (myText 兜底)
if (!decoded) {
    var rawText = null;
    if (data && data.uplink_message && data.uplink_message.decoded_payload && data.uplink_message.decoded_payload.myText) {
        rawText = data.uplink_message.decoded_payload.myText;
    } else if (data && data.myText) {
        rawText = data.myText;
    }

    if (rawText) {
        decoded = {};
        var parts = rawText.split(' ');
        parts.forEach(function(part) {
            var kv = part.split(':');
            if (kv.length !== 2) return;
            var key = kv[0];
            var value = parseFloat(kv[1]);
            if (isNaN(value)) return;
            switch (key) {
                case 'T':      decoded.temp = value; break;
                case 'H':      decoded.hum = value; break;
                case 'WBGT':   decoded.wetBulb = value; break;
                case 'W':      decoded.wetBulb = value; break; 
                case 'HSI':    decoded.risk = value; break;
                case 'R':      decoded.risk = value; break;    
                case 'FALL':   decoded.fall = value; break;
                case 'F':      decoded.fall = value; break;    
                case 'BAT':    decoded.battery = value; break;
            }
        });
    }
}

if (!decoded) {
    return { 
        error: "未能在数据中找到 frm_payload 或 myText 字段", 
        parsedData: data 
    };
}

// =========================
// 4. 装填 Telemetry
// =========================
if (decoded.temp !== undefined) telemetry.temp = decoded.temp;
if (decoded.hum !== undefined) telemetry.hum = decoded.hum;
if (decoded.wetBulb !== undefined) telemetry.wetBulb = decoded.wetBulb;
if (decoded.risk !== undefined) telemetry.risk = decoded.risk;
if (decoded.battery !== undefined) telemetry.battery = decoded.battery;
if (decoded.fall !== undefined) telemetry.fall = decoded.fall;
if (decoded.heartRateAvg !== undefined) telemetry.heartRateAvg = decoded.heartRateAvg;
if (decoded.usb !== undefined) telemetry.usb = decoded.usb;

// 新增 20 字节同步字段装填 (使用优化后的简短 Key)
if (decoded.localWBGT !== undefined) telemetry.locW = decoded.localWBGT;
if (decoded.externalWBGT !== undefined) telemetry.extW = decoded.externalWBGT;
if (decoded.skinTemp !== undefined) telemetry.skinTemp = decoded.skinTemp;
if (decoded.estimatedTc !== undefined) telemetry.tc = decoded.estimatedTc;
if (decoded.currentPSI !== undefined) telemetry.psi = decoded.currentPSI;
if (decoded.cumulativeHeatStrain !== undefined) telemetry.chs = decoded.cumulativeHeatStrain;

// 同时装载 decoded JSON 字符串以实现前端完美兼容 (使用超短 Key 压缩包体积)
var frontendDecoded = {
    telemetry: {
        temp: decoded.temp,
        hum: decoded.hum,
        wetBulb: decoded.wetBulb,
        battery: decoded.battery,
        fall: decoded.fall,
        heartrate: decoded.heartRateAvg,
        risk: decoded.risk,

        locW: decoded.localWBGT,
        extW: decoded.externalWBGT,
        skT: decoded.skinTemp,
        tc: decoded.estimatedTc,
        psi: decoded.currentPSI,
        chs: decoded.cumulativeHeatStrain
    }
};
telemetry.decoded = JSON.stringify(frontendDecoded);

// =========================
// 5. 提取元数据 (如果有)
// =========================
if (data && data.uplink_message) {
    telemetry.f_cnt = data.uplink_message.f_cnt || 0;
    if (data.uplink_message.rx_metadata && data.uplink_message.rx_metadata.length > 0) {
        var rx = data.uplink_message.rx_metadata[0];
        telemetry.rssi = rx.rssi;
        telemetry.snr = rx.snr;
    }
    if (data.uplink_message.settings && data.uplink_message.settings.data_rate && data.uplink_message.settings.data_rate.lora) {
        attributes.sf = data.uplink_message.settings.data_rate.lora.spreading_factor;
    }
}
if (data && data.end_device_ids && data.end_device_ids.dev_eui) {
    attributes.dev_eui = data.end_device_ids.dev_eui;
}
telemetry.active_signal = 1;

return {
    deviceName: deviceName,
    deviceType: "HeatStress-Node",
    telemetry: telemetry,
    attributes: attributes
};

configuration.tbelDecoder:
/**
 * Decodes the incoming payload and returns a structured object containing telemetry data and attributes.
 *
 * @param {byte[]} input - The raw payload received as an array of bytes.
 * @returns {Object} output - The structured output with decoded telemetry and attributes.
 */

function decodePayload(input) {
    // Initialize the output object with empty attributes and telemetry for clarity.
    var result = { attributes: {}, telemetry: {}};

    // Detect input type and normalize to byte array
    var bytes;

    if (metadata.payloadFormat == 'JSON') {
        // payloadFormat is 'JSON' when The Things Network payload formatters are configured on the application or device level.
        // In that case, decoded_payload is a JSON object produced by your formatter.
        // This template assumes the formatter returns { "bytes": [...] } with the raw byte array.
        // If your formatter returns pre-decoded values in a different structure,
        // update this section to extract the values directly from 'parsed' instead.
        var parsed = decodeToJson(input);
        if (parsed.bytes == null) {
            throw new Error("Payload formatter output does not contain a 'bytes' field. " +
                "Update this decoder to match your formatter's output structure.");
        }
        bytes = parsed.bytes;
    } else {
        // payloadFormat is 'BINARY' when no payload formatter is configured — raw bytes from frm_payload are passed directly.
        bytes = input;
    }

    // Decode serial number (SN) from the first 4 bytes of the payload.
    // Press '?' icon in the top right corner to learn more about built in helper functions and capabilities.
    result.attributes.sn = parseBytesToInt(bytes, 0, 4);

    // Extract the timestamp from metadata (represented in milliseconds).
    var timestamp = metadata.ts; // ts is the timestamp parsed from the incoming message's time, or returns the current time if it cannot be parsed.

    // Combine the timestamp with decoded values and add it to the telemetry.
    result.telemetry = {
        ts: timestamp,
        values: {
            // Decode battery level from the 5th byte of the payload.
            battery: parseBytesToInt(bytes, 4, 1),
            // Decode temperature from the 6th and 7th bytes of the payload (divided by 100).
            temperature: parseBytesToInt(bytes, 5, 2) / 100.0,
            // Decode saturation from the 8th byte of the payload.
            saturation: parseBytesToInt(bytes, 7, 1)
        }
    };

    // Return the fully constructed output object.
    return result;
    // Same logic, less code:
    // return {
    //     attributes: {
    //         sn: parseBytesToInt(bytes, 0, 4)
    //     },
    //     telemetry: {
    //         ts: convertDateToTimestamp(extractDateFromMetadata()),
    //         values: {
    //             battery: parseBytesToInt(bytes, 4, 1),
    //             temperature: parseBytesToInt(bytes, 5, 2) / 100.0,
    //             saturation: parseBytesToInt(bytes, 7, 1)
    //         }
    //     }
    // };
}

var result = decodePayload(payload);
// Uncomment this code block to overwrite values set in the main configuration window. Useful if you extract device/asset/customer/group names from the payload;
// result.type = 'DEVICE'; // Entity type allows you to choose type of created entity. Can be 'DEVICE' or 'ASSET'.
// result.name = 'Temperature Sensor'; // Device or asset name (the value must be unique)
// result.profile = 'IndustrialSensorProfile'; // Device or asset profile name.
// result.customer = 'MyCustomer'; // If customer is not null - created entity will be assigned to customer with such name.
// result.group = 'SensorsGroup'; // If group is not null - created entity will be added to the entity group with such name.

// Return the final result object.
return result;
